clinvar_dir <- paste0(annot_dir,"/clinvar_tables_extended") ### Directory containing one CLINVAR table per gene 

annotate_variant <- function(var) {
  
  gene <- sub("_.*", "", var)
  query <- sub(".*_[pc]\\.", "", var)
  
  file <- file.path(clinvar_dir, paste0(gene, ".txt"))
  
  if (!file.exists(file)) {
    return(data.frame(
      unique_variants = var,
      gene = gene,
      query = query,
      match_status = "gene_file_not_found",
      stringsAsFactors = FALSE
    ))
  }
  
  df <- read_tsv(
    file,
    col_types = cols(.default = col_character()),
    show_col_types = FALSE,
    name_repair = "unique"
  )
  
  hits <- df[grep(query, df$Name, fixed = TRUE), , drop = FALSE]
  
  if (nrow(hits) == 0) {
    return(data.frame(
      unique_variants = var,
      gene = gene,
      query = query,
      match_status = "no_match",
      stringsAsFactors = FALSE
    ))
  }
  
  hits$unique_variants <- var
  hits$gene <- gene
  hits$query <- query
  hits$match_status <- ifelse(nrow(hits) == 1, "matched", "multiple_matches")
  
  hits
}

