prkn_exon_summary <- rear_prkn %>%
  mutate(
    prkn_exon_raw = str_replace_all(unique_variants, "–|_", "-"),
    prkn_exon_raw = str_extract(prkn_exon_raw, "Ex[0-9P-]+"),
    prkn_exon_raw = str_remove(prkn_exon_raw, "^Ex"),
    prkn_exon = map(prkn_exon_raw, \(x) {
      if (is.na(x) || str_detect(x, "P")) return(NA_integer_)
      if (str_detect(x, "-")) {
        bounds <- as.numeric(str_split(x, "-", simplify = TRUE))
        seq(bounds[1], bounds[2])
      } else {
        as.numeric(x)
      }
    })
  ) %>%
  unnest(prkn_exon) %>%
  filter(!is.na(prkn_exon))

