table(str_extract(unique(prkn_exon_summary$unique_variants), "del|dup|inv")) ##types or rearrs in PRKN

###### check span of exon rearrangements: 
sv_prks_span <- tibble(x = unique(prkn_exon_summary$unique_variants)) %>%
  mutate(
    start = as.integer(str_extract(x, "(?<=Ex)\\d+")),
    end   = as.integer(str_extract(x, "(?<=-)\\d+")),
    end   = ifelse(is.na(end), start, end),
    n_exons = end - start + 1
  )

sv_prks_span

