############################################################################## Population stratification

table(OTHERS_raw$Population)

OTHERS_raw <- OTHERS_raw %>%
  mutate(
    Population_clean = str_to_lower(Population),
    Population_continent = case_when(
      
      # EUROPE
      str_detect(Population_clean, "europe|caucasian|french|german|irish|italian|italy|polish|serbian|swiss|uk|ukrainian|czech|netherlands|polish|finnland|france|belgian|spain|norway") ~ "EUR",
      
      #Middle East
      str_detect(Population_clean, "cyprus|turkish|yemen") ~ "MDE",
      
      # EAST ASIA
      str_detect(Population_clean, "china|chinese|japan|japanese|korea|korean|taiwan|vietnam|filipino") ~ "EAS",
      
      # AFRICA
      str_detect(Population_clean, "african|tunisia") ~ "AFR",
      
      # LATIN AMERICA / ADMIXED AMERICAN
      str_detect(Population_clean, "mexico|mexican|brazil|peru") ~ "AMR",
      
      # NORTH AMERICA (ambiguous, likely EUR )
      str_detect(Population_clean, "north american") ~ "EUR",
      
      TRUE ~ "Other"
    )
  )



table(OTHERS_raw$Population_continent)

pairs_by_continent <- OTHERS_raw %>%
  filter(!is.na(var_1_g), !is.na(var_2_g), !is.na(Population_continent)) %>%
  mutate(
    var_a = pmin(var_1_g, var_2_g),
    var_b = pmax(var_1_g, var_2_g)
  ) %>%
  count(Population_continent, var_a, var_b, sort = TRUE)

top_pairs_by_continent <- pairs_by_continent %>%
  group_by(Population_continent) %>%
  slice_max(n, n = 5, with_ties = FALSE) %>%
  ungroup()

top_pairs_by_continent


###### check exclusivity

pair_exclusivity <- pairs_by_continent %>%
  group_by(var_a, var_b) %>%
  mutate(n_continents = n_distinct(Population_continent)) %>%
  ungroup()
exclusive_pairs <- pair_exclusivity %>%
  filter(n_continents == 1)

exclusive_pairs %>%
  arrange(Population_continent, desc(n))

exclusive_summary <- pairs_by_continent %>%
  group_by(var_a, var_b) %>%
  mutate(n_continents = n_distinct(Population_continent)) %>%
  ungroup() %>%
  mutate(is_exclusive = n_continents == 1) %>%
  group_by(Population_continent) %>%
  summarise(
    total_pairs = n(),                         # number of distinct pairs in that continent
    exclusive_pairs = sum(is_exclusive),       # how many are exclusive
    prop_exclusive = exclusive_pairs / total_pairs
  )

exclusive_summary


